namespace HECUVoiceLab.Analysis;
public static class MatchScorer { public static (int Score,string Hints) Score(AnalysisResult a, AnalysisResult t){ double score=100; score-=Math.Abs(a.ActiveRmsDb-t.ActiveRmsDb)*2; score-=Math.Abs(a.PeakDb-t.PeakDb)*1.5; for(int i=0;i<a.Bands.Length;i++)score-=Math.Abs(a.Bands[i]-t.Bands[i])*.8; for(int i=0;i<a.Rolloffs.Length;i++)score-=Math.Abs(a.Rolloffs[i]-t.Rolloffs[i])/500; var hints=new List<string>(); if(a.Bands[5]+a.Bands[6]>t.Bands[5]+2)hints.Add("Too much energy above 5500 Hz: lower Low-Pass Frequency."); if(a.Bands[1]<t.Bands[1]-5)hints.Add("Too little 300–800 Hz energy: increase Helmet Low-Mid Boost."); if(a.PeakDb>-6)hints.Add("Too loud/clipping: lower Output Gain or Makeup Gain."); if(a.ActiveRmsDb<-24)hints.Add("Too quiet: raise Makeup Gain or Output Gain."); if(!hints.Any())hints.Add("Close match: fine-tune crunch and chop by taste."); return ((int)Math.Clamp(score,0,100),string.Join('\n',hints));}}
